diff --git a/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp b/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
index 384f38b2c5362..9d9192d49d5ce 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
@@ -331,6 +331,41 @@ Instruction *InstCombinerImpl::visitMul(BinaryOperator &I) {
   if (Value *FoldedMul = foldMulSelectToNegate(I, Builder))
     return replaceInstUsesWith(I, FoldedMul);

+  // (shl X, C1)*(select cond, C2, C3)--> X * (select cond, C2<<C1, C3<<C1)
+  // (mul X, C1)*(select cond, C2, C3)--> X * (select cond, C2*C1, C3*C1)
+  // (Includes commuted forms)
+
+  {
+    Value *NewOp, *Cond, *OtherValue;
+    Constant *C1, *C2, *C3;
+
+    if (match(&I, m_c_Mul(m_OneUse(m_Value(OtherValue)),
+                          m_OneUse(m_Select(m_Value(Cond), m_Constant(C2),
+                                            m_Constant(C3))))) &&
+        (match(OtherValue, m_c_Mul(m_Value(NewOp), m_Constant(C1))) ||
+         match(OtherValue, m_Shl(m_Value(NewOp), m_Constant(C1))))) {
+
+      auto *OtherInst = cast<OverflowingBinaryOperator>(OtherValue);
+      auto Opc = OtherInst->getOpcode();
+
+      Constant *NewTV = ConstantFoldBinaryOpOperands(Opc, C2, C1, DL);
+      Constant *NewFV = ConstantFoldBinaryOpOperands(Opc, C3, C1, DL);
+
+      if (NewTV && NewFV) {
+        Value *NewSel = Builder.CreateSelect(Cond, NewTV, NewFV);
+        BinaryOperator *BO = BinaryOperator::CreateMul(NewOp, NewSel);
+
+        if (HasNUW && OtherInst->hasNoUnsignedWrap())
+          BO->setHasNoUnsignedWrap();
+        if (HasNSW && OtherInst->hasNoSignedWrap() &&
+            NewTV->isNotMinSignedValue() && NewFV->isNotMinSignedValue())
+          BO->setHasNoSignedWrap();
+
+        return BO;
+      }
+    }
+  }
+
   // Simplify mul instructions with a constant RHS.
   Constant *MulC;
   if (match(Op1, m_ImmConstant(MulC))) {

tests.test_body:
define i16 @shl_select_mul(i16 %x, i1 %cond) {
  %shl = shl i16 %x, 2
  %sel = select i1 %cond, i16 5, i16 3
  %mul = mul i16 %shl, %sel
  ret i16 %mul
}

define i16 @shl_select_no_flags(i16 %x, i1 %cond) {
  %shl = shl nsw i16 %x, 2
  %sel = select i1 %cond, i16 5, i16 3
  %mul = mul i16 %shl, %sel
  ret i16 %mul
}

define i32 @pow2_multiplier(i32 %A) {
  %B = mul i32 %A, 2
  ret i32 %B
}

define i16 @mul_select_mul(i16 %x, i1 %cond) {
  %mul1 = mul i16 %x, 3
  %sel = select i1 %cond, i16 4, i16 2
  %mul = mul i16 %mul1, %sel
  ret i16 %mul
}

define i32 @mul_sext_bool(i1 %x) !prof !0 {
  %s = sext i1 %x to i32
  %m = mul i32 %s, 42
  ret i32 %m
}

!0 = !{!"function_entry_count", i64 1000}

define <4 x i16> @shl_select_vec_non_splat(<4 x i16> %x, i1 %cond) {
  %shl = shl <4 x i16> %x, <i16 1, i16 2, i16 3, i16 4>
  %sel = select i1 %cond, <4 x i16> <i16 5, i16 3, i16 7, i16 1>, <4 x i16> <i16 2, i16 4, i16 6, i16 8>
  %mul = mul <4 x i16> %shl, %sel
  ret <4 x i16> %mul
}

define noundef i64 @shl_select_zero_arm(i64 %0, i1 %1) {
  %3 = select i1 %1, i64 2, i64 0
  %4 = shl i64 %0, 1
  %5 = mul i64 %4, %3
  ret i64 %5
}

define <4 x i16> @shl_select_vec_splat(<4 x i16> %x, i1 %cond) {
  %shl = shl <4 x i16> %x, splat (i16 2)
  %sel = select i1 %cond, <4 x i16> splat (i16 5), <4 x i16> splat (i16 3)
  %mul = mul <4 x i16> %shl, %sel
  ret <4 x i16> %mul
}

define i16 @mul_udiv_zext_uneq(i8 %x) {
  %div = udiv i8 %x, 20
  %zext = zext i8 %div to i16
  %mul = mul i16 %zext, 15
  ret i16 %mul
}

define <4 x i16> @shl_select_vector_with_poison(<4 x i16> %x, i1 %cond) {
  %shl = shl <4 x i16> %x, <i16 2, i16 poison, i16 poison, i16 2>
  %sel = select i1 %cond, <4 x i16> <i16 5, i16 poison, i16 5, i16 5>, <4 x i16> <i16 3, i16 poison, i16 3, i16 3>
  %mul = mul <4 x i16> %shl, %sel
  ret <4 x i16> %mul
}

define i16 @shl_select_commuted(i16 %x, i1 %cond) {
  %shl = shl i16 %x, 2
  %sel = select i1 %cond, i16 5, i16 3
  %mul = mul i16 %sel, %shl
  ret i16 %mul
}

define i16 @shl_select_nuw_only(i16 %x, i1 %cond) {
  %shl = shl i16 %x, 2
  %sel = select i1 %cond, i16 5, i16 3
  %mul = mul nuw i16 %shl, %sel
  ret i16 %mul
}

define i16 @shl_select_both_nuw_nsw(i16 %x, i1 %cond) {
  %shl = shl nuw nsw i16 %x, 2
  %sel = select i1 %cond, i16 5, i16 3
  %mul = mul nuw nsw i16 %shl, %sel
  ret i16 %mul
}

define <4 x i16> @mul_select_vec_splat(<4 x i16> %x, i1 %cond) {
  %mul1 = mul <4 x i16> %x, splat (i16 3)
  %sel = select i1 %cond, <4 x i16> splat (i16 4), <4 x i16> splat (i16 2)
  %mul = mul <4 x i16> %mul1, %sel
  ret <4 x i16> %mul
}
